import React from 'react';
import emailjs from 'emailjs-com';
import { Formik, Form, Field, ErrorMessage } from 'formik';
import * as Yup from 'yup';
import confetti from 'canvas-confetti';
import LottieAnimation from './animation';

import './FourthSection.css';

const validationSchema = Yup.object().shape({
  name: Yup.string().required('Name is required'),
  email: Yup.string().email('Invalid email').required('Email is required'),
  subject: Yup.string().required('Subject is required'),
  message: Yup.string().required('Message is required'),
});

const FourthSection = () => {
  const sendEmail = (values, { setSubmitting, resetForm }) => {
    const { name, email, subject, message } = values;

    emailjs.sendForm('service_hpeadoj', 'template_doikkmo', 'form', 'mxhVfavVsSqczEg8r')
      .then((result) => {
        console.log(result.text);
        confetti({
          origin: {
            x: 0.5,
            y: 0.5
          },
          spread: 90
        });
        setSubmitting(false);
      })
      .catch((error) => {
        console.log(error.text);
        setSubmitting(false);
      });
    resetForm();
  };

  return (
    <div className='fourthsection' data-aos="zoom-out-up">
      <LottieAnimation loop={false} src={require('../resources/contactcircles.json')} style={{ position: 'absolute', width: '40vw', zIndex: '-1' }} speed2={1} />
      <div className='grid-container'>
        <h2 style={{ padding: '15px', boxShadow: 'rgb(223 225 255 / 66%) 1px 1px 20px 6px', background: 'whitesmoke' }} data-aos="fade-up"> Contact me. 🤝</h2>
        <div />
        <p style={{ textAlign: 'left' }}>
          {/* ... */}
        </p>
        <Formik
          initialValues={{ name: '', email: '', subject: '', message: '' }}
          validationSchema={validationSchema}
          onSubmit={sendEmail}
        >
          {({ isSubmitting }) => (
            <Form className='contactmebox' id='form'>
              <h3 style={{ color: 'white' }}>Get in touch.</h3>
              <div className='input-row'>
                <Field type="text" name='name' className='textBox' placeholder="name" />
                <Field type="text" name='email' className='textBox' placeholder="email" />
              </div>
              <ErrorMessage name='name' component='div' className='error' />
              <ErrorMessage name='email' component='div' className='error' />
              <Field type="text" name='subject' className='textBox' placeholder="subject" />
              <ErrorMessage name='subject' component='div' className='error' />
              <Field as='textarea' name='message' className='textBox' placeholder="message" />
              <ErrorMessage name='message' component='div' className='error' />
              <button type="submit" className={`submitbutton ${isSubmitting ? 'submitting' : ''}`} id="submitbutton">
                {isSubmitting ? 'Submitting...' : 'Submit'}
              </button>
            </Form>
          )}
        </Formik>
      </div>
    </div>
  );
};

export default FourthSection;
